from flask import Flask, request, jsonify
import json
import os
from datetime import datetime, timedelta

app = Flask(__name__)

CACHE_DIR = 'cache'
if not os.path.exists(CACHE_DIR):
    os.makedirs(CACHE_DIR)

def load_cache(key):
    cache_path = os.path.join(CACHE_DIR, key)
    if os.path.exists(cache_path):
        with open(cache_path, 'r') as f:
            data = json.load(f)
            if datetime.now() < datetime.fromtimestamp(data['expires']):
                return data['value']
    return None

def save_cache(key, value, ttl=3600):
    cache_data = {
        'value': value,
        'expires': (datetime.now() + timedelta(seconds=ttl)).timestamp()
    }
    with open(os.path.join(CACHE_DIR, key), 'w') as f:
        json.dump(cache_data, f)

@app.route('/api', methods=['GET'])
def api():
    url = request.args.get('url')
    if not url:
        return jsonify({'error': 'URL parameter is required'}), 400

    cached_response = load_cache(url)
    if cached_response:
        return jsonify(cached_response)

    # Simulate an expensive API call
    expensive_api_response = {
        'data': {
            'items': [1, 2, 3],
            'metadata': {'timestamp': datetime.now().isoformat()}
        }
    }

    save_cache(url, expensive_api_response)
    return jsonify(expensive_api_response)

